from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
import numpy as np
import re
import joblib
import os

app = Flask(__name__)

# Load or train the model
def train_model():
    # Sample dataset
    emails = ["Free money now!!!", "Hi, how are you?", "Get rich quick!", "Meeting at 10am tomorrow."]
    labels = [1, 0, 1, 0]  # 1 for spam, 0 for ham

    vectorizer = CountVectorizer()
    X = vectorizer.fit_transform(emails)
    model = LogisticRegression()
    model.fit(X, labels)

    joblib.dump(model, 'spam_model.pkl')
    joblib.dump(vectorizer, 'vectorizer.pkl')

# Load the model and vectorizer
if not os.path.exists('spam_model.pkl') or not os.path.exists('vectorizer.pkl'):
    train_model()

model = joblib.load('spam_model.pkl')
vectorizer = joblib.load('vectorizer.pkl')

def clean_input(text):
    # Basic input validation and cleaning
    text = re.sub(r'[^a-zA-Z0-9\s]', '', text)
    return text.strip()

@app.route('/predict', methods=['POST'])
def predict():
    if not request.json or 'email' not in request.json:
        return jsonify({'error': 'Invalid input'}), 400

    email_text = clean_input(request.json['email'])
    email_vector = vectorizer.transform([email_text])
    probability = model.predict_proba(email_vector)[0][1]

    return jsonify({'spam_probability': probability})

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use SSL for secure transport